    /// <summary>True after <see cref="TakeOwnership"/> has been called.</summary>
    public static bool IsReleased => _data is null;

    /// <summary>Read-only view while still loaded. Throws after <see cref="TakeOwnership"/>.</summary>
    public static IReadOnlyDictionary<string, Sin> ById
        => _data ?? throw new System.InvalidOperationException(
            "CardSinMap has been released. Use a runtime registry instead.");

    /// <summary>
    /// One-time ownership transfer. Returns the underlying Dictionary and
    /// nulls out the static reference so the GC can reclaim it once the caller
    /// drops its reference. Calling a second time throws.
    /// </summary>
    public static Dictionary<string, Sin> TakeOwnership()
    {
        var data = _data ?? throw new System.InvalidOperationException(
            "CardSinMap.TakeOwnership already called.");
        _data = null;
        return data;
    }
